import React, { useState, useEffect } from 'react';

const Timer = ({ initialSeconds, onTimeUp, isActive }) => {
  const [seconds, setSeconds] = useState(initialSeconds);

  useEffect(() => {
    if (!isActive) return;

    const interval = setInterval(() => {
      setSeconds(prev => {
        if (prev <= 1) {
          clearInterval(interval);
          onTimeUp();
          return 0;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(interval);
  }, [isActive, onTimeUp]);

  const formatTime = () => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const getColor = () => {
    if (seconds < 60) return '#c53030'; // Red - less than 1 minute
    if (seconds < 300) return '#b45f06'; // Orange - less than 5 minutes
    return '#1a202c'; // Dark gray - normal
  };

  return (
    <span style={{ 
      fontFamily: 'monospace',
      fontSize: '20px',
      fontWeight: '600',
      color: getColor(),
      backgroundColor: seconds < 60 ? '#fff5f5' : 'transparent',
      padding: seconds < 60 ? '4px 10px' : '0',
      borderRadius: '6px'
    }}>
      {formatTime()}
    </span>
  );
};

export default Timer;
